const items = $input.all();
const d = items[0]?.json || {};
const peers = items.slice(1).map(i => i.json).filter(p => p.peer_ticker);

let peerInfo = '';
if (peers.length > 0) {
  peerInfo = '

Industry Peers (from Neo4j graph):';
  for (const p of peers) {
    peerInfo += `
- ${p.peer_name} (${p.peer_ticker})${p.on_watchlists?.length ? ' [on: ' + p.on_watchlists.join(', ') + ']' : ''}`;
  }
}

return [{json:{ticker:d.ticker,context:`Value analysis:
Ticker: ${d.ticker} (${d.company_name})
Sector: ${d.sector} | Industry: ${d.industry} | Cap: $${(d.market_cap/1e9).toFixed(1)}B
P/E: ${d.pe_ratio} | P/B: ${d.pb_ratio} | P/S: ${d.ps_ratio}
D/E: ${d.debt_to_equity} | CR: ${d.current_ratio}
ROE: ${(d.roe*100).toFixed(1)}% | ROA: ${(d.roa*100).toFixed(1)}%
Rev: $${(d.revenue/1e9).toFixed(2)}B | Net: $${(d.net_income/1e6).toFixed(0)}M
FCF: $${(d.free_cash_flow/1e6).toFixed(0)}M | Yield: ${(d.dividend_yield*100).toFixed(2)}%${peerInfo}
Date: ${new Date().toISOString().split('T')[0]}

Use peer comparison for relative valuation. Calculate intrinsic value, margin of safety, check value traps.`}}];
